import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "監控室在行政樓地下半層，要往下走一段很窄的樓梯。牆壁上的油漆剝落了大半，露出底下灰色的水泥。空氣裡有一種潮濕的電子設備味——塑膠外殼受熱之後散發的那種微甜的焦味，混著地下水的霉。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔帶他下來的時候說了一句：「你跟著就好，不用說話。」", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言沒有說話。但他的眼睛，一直在動。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)監控室。鐘樓的攝像頭在這裡。裝卸區的攝像頭在這裡。整個校園的眼睛，都在這幾面螢幕上。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "監控室不大，大概十來坪。三面牆上掛著九面螢幕，型號新舊混雜——左邊三台是較新的液晶螢幕，畫面清晰，色彩正常；右邊三台是舊式的映像管螢幕，畫面偏綠，邊緣有一圈暗角；中間三台混合著雜訊和切換後的藍屏。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "桌前坐著一個年輕人，穿著深藍色的技術志工背心，胸前別著一張列印的臨時工作證。他正在一台舊筆電前操作，手指在鍵盤上飛快地敲著，但螢幕上的畫面進展得很慢。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "麻煩調一下鐘樓和裝卸區今天的紀錄。從早上六點開始。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.ShaoQiming_Serious },
    { characterId: CharacterId.Technician, character: "技術人員", dialogue: "好，我調一下⋯⋯系統今天比較慢，大雨一直讓它切備援線。你們等一下。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "技術人員的聲音帶著一種忙到麻木的平靜。他一邊操作一邊解釋，像是在做一份他已經重複了很多次的工作。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕上的畫面開始跳。鐘樓的鏡頭切到裝卸區，又跳到南翼走廊，然後整個黑了一秒，再亮起來的時候變成了校門口的畫面。技術人員罵了一聲，又重新切回鐘樓。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Technician, character: "技術人員", dialogue: "今天雨太大，舊系統一直在主線和備用線之間切。一切線就要重新同步緩衝，那段時間看不到即時回放。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)切線。緩衝。看不到。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "多久？", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有要追問的意思。只是一個短句，平得像在問今天星期幾。但他的眼睛盯著技術人員的螢幕，一眨不眨。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Technician, character: "技術人員", dialogue: "這次⋯⋯十七分鐘。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)十七。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)十七分鐘。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那三個字像三根釘子，釘進他的腦子裡。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一輪。鐘樓停電前後。監控有空白。我那時候以為是停電造成的。但——停電前就已經斷了？還是停電後才斷的？我記不清了。我只記得當時沒人在意那段空白。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第二輪。裝卸區。校務車出發前後。畫面有缺失。我那時候以為是角度問題。但——裝卸區的攝像頭不是壞了，是那段時間根本沒有紀錄。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)兩次。兩段空白。都在關鍵事件前後。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)現在他告訴我：舊系統切線，固定會有十七分鐘看不到。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)十七分鐘。一個固定的、可預測的空白。任何人只要知道這個系統什麼時候會切線，就可以把任何行動塞進那十七分鐘裡。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任站在邵叔身後兩步遠的地方，雙手插在西裝褲口袋裡，肩膀微微聳起，像在忍受一件他不想在場的事。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "老系統了，颱風天很正常。今天不要把所有小問題都當陰謀。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.LinZhuren_Stern },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的語氣比在指揮區時放鬆了一些。少了那種被邵叔壓住之後的僵硬。像是一個人在覺得安全的環境裡，又找回了那套官腔。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)林主任。他又在壓。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)第一輪他壓我的問題。第二輪他壓車輛表的異常。第三輪他在壓監控空白。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)每一次有什麼東西對不上，他都會跳出來說「很正常」。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "技術人員終於把鐘樓的畫面調出來了。畫質很差，灰綠色的，像隔了一層髒玻璃。時間戳記顯示 06:48 到 07:05 之間，畫面是正常的——鐘樓外牆、維修門、北側樓梯入口，都是空的。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後 07:05 過後，畫面開始卡。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是突然斷掉的那種黑，而是一格一格地跳。像有人按了暫停，等了幾秒，再按播放，再暫停。技術人員皺著眉，把播放速度調慢。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "在兩格跳動之間——大概只有零點幾秒的間隙——顧言看見了。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)那個⋯⋯", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鐘樓維修門前。有人。那人背對鏡頭，穿著深色雨衣，正在往門上貼一張紙。白色的紙。格式像是臨時告示。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後畫面斷了。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是暗掉，不是黑屏。是直接跳到了下一個時間戳——07:22。中間十七分鐘的紀錄，一片空白。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)有人貼了告示。但看不到是誰。他剛好出現在斷線前的最後幾格。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)是巧合？還是他知道攝像頭什麼時候會斷？", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "技術人員切到裝卸區的畫面。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這段更糟。06:30 到 07:15 之間是正常的——黑色器材箱整齊排列在雨棚下，有工作人員進出搬東西。然後 07:15 之後，畫面變成一片雪花。等到重新恢復的時候，已經是 07:32。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "又是十七分鐘。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但恢復後的畫面裡，器材箱的位置變了。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯移動了。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)斷線前，那三個黑色器材箱在雨棚左側，排成一行。恢復之後，最右邊那個箱子的位置往後移了大約一米。中間過程——完全空白。沒有人影，沒有搬運，什麼都沒有。只有結果。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)箱子被人移動了。但移動的過程，被十七分鐘的空白吃掉了。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第三段。南翼醫務室走廊。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這段的畫面比前兩段好一些——至少沒有完全斷訊，只是畫質很差，人影模糊得像水裡的倒影。時間戳記從 07:40 到 08:10。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:52，走廊畫面裡出現了一個人。穿著深灰色西裝。金屬框眼鏡反射著走廊燈光。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯林主任？", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不。不完全確定。那個人從鏡頭右側進入，走向南翼醫務室方向，然後畫面又開始卡。等畫面穩下來的時候，走廊已經空了。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)行政組的人員。進出南翼醫務室。時間在斷線前後。畫面不完整。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)鐘樓有人貼告示。裝卸區有箱子被移動。南翼走廊有人進出。全部發生在十七分鐘的空白前後。全部只有殘片，沒有過程。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果有人知道舊系統的切線時間，他就可以在這十七分鐘裡做任何事。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔站在螢幕前，雙手背在身後，表情平靜。他看了三段畫面，一句話也沒有說。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "這些紀錄先保留。不要覆蓋。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.ShaoQiming_Serious },
    { characterId: CharacterId.Technician, character: "技術人員", dialogue: "好。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "今天每一次切線，你都記下時間。精確到秒。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.ShaoQiming_Serious },
    { characterId: CharacterId.Technician, character: "技術人員", dialogue: "⋯⋯好。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "技術人員的語氣有些遲疑。他大概沒有被這樣要求過。但他還是點了點頭，在鍵盤旁邊的便條紙上寫了「07:05-07:22」和「07:15-07:32」兩個時間段。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔轉身，看了一眼顧言。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.ShaoQiming, character: "邵叔", dialogue: "走吧。帶你去個安靜的地方。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.ShaoQiming_Concerned },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言從椅子上站起來，跟在邵叔身後往樓梯走。經過林主任身邊的時候，他聞到了一股很淡的煙味。不是菸味。是那種辦公室裡列印機過熱之後的焦味。林主任的衣服上，沾著那種味道。", background: Background.Chapter_3_Ch3_Act6_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)十七分鐘。我記住了。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)一個舊系統的固定漏洞。一個可以被任何人利用的窗口。關鍵不是漏洞存不存在。關鍵是——誰知道它什麼時候會打開。", background: Background.Chapter_3_Ch3_Act6_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他走上樓梯。身後的監控室裡，九面螢幕繼續閃爍著。灰綠色的、破碎的、充滿雜訊的畫面，像九隻瞎了的眼睛，在暴雨裡反覆眨動。", background: Background.Chapter_3_Ch3_Act6_S0 },
];
